const alert = $input.first().json;
const alertStatus = alert.status || 'firing';
const now = new Date();
const fiveMinAgo = new Date(now.getTime() - 5 * 60 * 1000);
const startNano = (fiveMinAgo.getTime() * 1_000_000).toString();
const endNano = (now.getTime() * 1_000_000).toString();
function toKst(d) {
  const k = new Date(d.getTime() + 9 * 3600 * 1000);
  return `${k.getUTCFullYear()}-${String(k.getUTCMonth()+1).padStart(2,'0')}-${String(k.getUTCDate()).padStart(2,'0')} ${String(k.getUTCHours()).padStart(2,'0')}:${String(k.getUTCMinutes()).padStart(2,'0')}`;
}
const timeRangeKst = `${toKst(fiveMinAgo)} ~ ${toKst(now)} (KST)`;
return [{ json: { alertStatus, startNano, endNano, timeRangeKst } }];

const lokiResponse = $input.first().json;
const alertInfo = $('Parse Alert').first().json;

const tagChannelMap = {
  RAG_REINDEX:        '#ai-alert',
  EMBEDDING_FAIL:     '#ai-alert',
  AUCTION_ANOMALY:    '#business-insight',
  PAYMENT_ESCALATION: '#business-insight',
  CACHE:              '#backend',
  RATE_LIMIT:         '#backend',
  ES_INDEXING:        '#backend',
  ES_MIGRATION:       '#backend',
  CARD_SYNC:          '#backend',
  FAKFA_FAIL:         '#backend',
  SLOW_QUERY:         '#backend',
  DATA_SEEDING:       '#backend',
  DEFAULT:            '#error-alert',
};

const fmt = '\n\n출력 형식 — Slack mrkdwn 규칙:\n- 굵게는 *텍스트* (별표 1개, **텍스트** 금지)\n- 인라인 코드는 `코드`\n- 헤더(#) 사용 금지, 가로 구분선(---) 사용 금지\n- 리스트는 • 으로 시작 (-, * 금지)\n- 한국어로 작성, :mag: 외 이모지 자제, 간결하게';

const sysPrompts = {
  RAG_REINDEX:        '당신은 POCAT AI RAG 재색인 장애 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 장애 요약* • 발생 시각/실패 유형/영향 범위\n:mag: *2. 원인 분석* • 벡터DB장애/락 경합/데이터이상 분류\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  EMBEDDING_FAIL:     '당신은 POCAT AI 임베딩 실패 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 장애 요약* • 발생 시각/실패 유형/영향 범위\n:mag: *2. 원인 분석* • 벡터DB장애/API한도초과/데이터이상/인프라문제 분류\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  AUCTION_ANOMALY:    '당신은 POCAT 경매 이상 거래 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 거래 요약* • 감지 시각/이상 유형/관련 경매·카드 ID\n:mag: *2. 이상 원인 분석* • 가격조작/봇의심/희귀카드정상거래/일시적시장변동 분류\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  PAYMENT_ESCALATION: '당신은 POCAT 결제 승격 장애 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 장애 요약* • 발생 시각/장애 유형/영향 사용자\n:mag: *2. 원인 분석* • 승격 처리 실패/알림 발송 실패/타임아웃 분류\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  CACHE:              '당신은 POCAT 캐시 장애 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 장애 요약* • 발생 시각/캐시 유형/영향 범위\n:mag: *2. 원인 분석* • Redis 장애/메모리 부족/네트워크 분류\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  RATE_LIMIT:         '당신은 POCAT Rate Limit 장애 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 장애 요약* • 발생 시각/우회된 Rate Limit 범위\n:mag: *2. 원인 분석* • Redis 장애로 보호장치 비활성 상태 확인\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  ES_INDEXING:        '당신은 POCAT Elasticsearch 색인 장애 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 장애 요약* • 발생 시각/색인 유형/영향 데이터\n:mag: *2. 원인 분석* • ES 클러스터 장애/네트워크/매핑 오류 분류\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  CARD_SYNC:          '당신은 POCAT 카드 동기화 장애 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 장애 요약* • 발생 시각/실패 유형/영향 세트·카드\n:mag: *2. 원인 분석* • 외부 API 장애/중복 데이터/네트워크 분류\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  FAKFA_FAIL:         '당신은 POCAT 카프카 장애 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 장애 요약* • 발생 시각/장애 유형/영향 토픽·컨슈머\n:mag: *2. 원인 분석* • 브로커장애/네트워크단절/컨슈머지연/역직렬화오류 분류\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  SLOW_QUERY:         '당신은 POCAT DB 슬로우 쿼리 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 쿼리 요약* • 발생 시각/쿼리 유형/영향 테이블\n:mag: *2. 원인 분석* • 인덱스 미적용/풀스캔/락 경합 분류\n:mag: *3. 최적화 방안* • *즉시* / *단기(인덱스)* / *장기(구조개선)* 각 한 문장' + fmt,
  DATA_SEEDING:       '당신은 POCAT 데이터 시딩 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 요약* • 시딩 시각/대상 데이터/처리 건수\n:mag: *2. 상태 분석* • 성공/실패 여부 및 원인\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
  DEFAULT:            '당신은 POCAT Spring Boot 애플리케이션 장애 분석 전문가입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 에러 요약* • 발생 시각/에러 유형/발생 위치\n:mag: *2. 원인 분석* • 근본 원인 추정\n:mag: *3. 조치 방안* • *즉시* / *단기* / *장기* 각 한 문장' + fmt,
};

let allLines = [];
if (lokiResponse.data && lokiResponse.data.result) {
  for (const stream of lokiResponse.data.result) {
    if (stream.values) {
      for (const [, line] of stream.values) allLines.push(line);
    }
  }
}

const tagGroups = {};
for (const line of allLines) {
  const match = line.match(/\[([A-Z_]+)\]/);
  const tag = (match && tagChannelMap[match[1]] !== undefined) ? match[1] : 'DEFAULT';
  if (!tagGroups[tag]) tagGroups[tag] = [];
  tagGroups[tag].push(line);
}

const maxChars = 5000;
return Object.entries(tagGroups).map(([tag, lines]) => {
  let logs = lines.join('\n---\n');
  if (logs.length > maxChars) logs = logs.substring(0, maxChars) + '\n... (truncated)';
  return { json: {
    tag,
    logCount: lines.length,
    channelName: tagChannelMap[tag] || tagChannelMap.DEFAULT,
    systemPrompt: sysPrompts[tag] || sysPrompts.DEFAULT,
    userPrompt: `[${tag}] 감지\n[Time Range] ${alertInfo.timeRangeKst}\n[Log Count] ${lines.length}건\n\n--- 로그 ---\n${logs}`,
    alertInfo,
  }};
});

const aiOutput = $input.first().json;
const original = $('Group by Tag').item.json;
let analysis = aiOutput.output || aiOutput.text || '분석 실패';
analysis = analysis
  .replace(/\*\*(.+?)\*\*/g, '*$1*')
  .replace(/^\s*#+\s+/gm, '')
  .replace(/^\s*-{3,}\s*$/gm, '')
  .replace(/\n{3,}/g, '\n\n');
const text = `:rotating_light: *[${original.tag}] ERROR 감지*\n\n*Time:* ${original.alertInfo.timeRangeKst}\n*Log Count:* ${original.logCount}건\n\n${analysis}`;
return [{ json: { text, channelName: original.channelName } }];
